#include <assert.h>
#include <string.h>
#include "../src/sds.h"

void test_sdsnew(void) {
    sds s = sdsnew("hello");
    assert(sdslen(s) == 5);
    assert(strcmp(s, "hello") == 0);
    sdsfree(s);
}

void test_sdscat(void) {
    sds s = sdsnew("hello");
    s = sdscat(s, " world");
    assert(sdslen(s) == 11);
    assert(strcmp(s, "hello world") == 0);
    sdsfree(s);
}

void test_sdslen(void) {
    sds s = sdsempty();
    assert(sdslen(s) == 0);
    s = sdscat(s, "abc");
    assert(sdslen(s) == 3);
    sdsfree(s);
}

int main(void) {
    test_sdsnew();
    test_sdscat();
    test_sdslen();
    printf("All sds tests passed!\n");
    return 0;
}

sds sdsreverse(sds s) {
    size_t len = sdslen(s);
    if (len <= 1) return s;
    size_t i = 0, j = len - 1;
    while (i < j) {
        char tmp = s[i];
        s[i] = s[j];
        s[j] = tmp;
        i++;
        j--;
    }
    return s;
}
